class Solution:
    def repairCars(self, ranks: List[int], cars: int) -> int:
        def can_repair_all(time: int) -> bool:
            total = 0
            for r in ranks:
                total += int((time // r) ** 0.5)
                if total >= cars:
                    return True
            return total >= cars

        left, right = 0, min(ranks) * cars * cars
        while left < right:
            mid = (left + right) // 2
            if can_repair_all(mid):
                right = mid
            else:
                left = mid + 1
        return left
